@Hierarchy.source: {
  entity: 'I_OrganizationalUnit',
  parentChild: {
    parentElement: 'ParentOrgUnitID',
    childElement: 'OrgUnitID'
  },
  hierarchy: {
    hierarchyType: #SOURCE,
    hierarchyName: 'Z_OrgUnitHierarchy'
  }
}
define view Z_OrgUnitHierarchy
  as select from I_OrganizationalUnit
{
  key OrgUnitID,
      ParentOrgUnitID,
      OrgUnitName,
      ValidityStartDate,
      ValidityEndDate
}

/*
  Querying the hierarchy from ABAP:
  SELECT HIERARCHY( OrgUnitID, ParentOrgUnitID,
                    root => 'CEO_001',
                    direction => #DOWN,
                    siblings_order => OrgUnitName ASC )
    FROM Z_OrgUnitHierarchy
    WHERE OrgUnitName LIKE '%Sales%'
    INTO TABLE @DATA(lt_org_hierarchy).

  Result includes: HierarchyLevel, HierarchyPath, HierarchyRank,
                   ParentHierarchyNode, NodeID, ParentNodeID
*/

@EndUserText.label: 'Cost Center Rollup Hierarchy'
@Hierarchy.source: {
  entity: 'I_CostCenter',
  parentChild: {
    parentElement: 'CostCenterID',
    childElement: 'SuperiorCostCenterID'
  },
  hierarchy: {
    hierarchyType: #RECURSIVE,
    hierarchyName: 'Z_CostCenterRollup',
    cycleHandling: #BREAK_AT_CYCLE,
    orphanHandling: #ERROR
  }
}
define view Z_CostCenterHierarchy
  as select from I_CostCenter
{
  key CostCenterID,
      SuperiorCostCenterID,
      CostCenterName,
      ControllingArea,
      ProfitCenterID
}

/*
  Cycle handling is critical for financial hierarchies:
  - #BREAK_AT_CYCLE: prevent infinite loops in cyclic hierarchies
  - OrphanHandling: #ERROR (fail) vs #ROOT (treat as root)
*/

