@EndUserText.label: 'Extended Sales Order View'
@AccessControl.authorizationCheck: #CHECK
extend view I_SalesOrder with Z_I_SalesOrder_Extension
{
  /*
    Add custom fields from extension include.
    The include structure Z_SALES_ORDER_EXT is appended to
    the standard table and the CDS view automatically picks it up.
  */
  Z_CustomField1 as CustomExtensionField1,
  Z_CustomField2 as CustomExtensionField2,

  /*
    Add calculated field using standard + custom fields.
  */
  @Semantics.quantity.unitOfMeasure: 'TotalNetAmountUnit'
  case when Z_CustomField1 is not null
    then TotalNetAmount * Z_CustomField1 / 100
    else TotalNetAmount
  end as AdjustedTotal,

  /*
    Add association to custom extension table.
  */
  association [0..*] to Z_CustomSalesAttachment as _CustomAttachment
    on $projection.SalesOrderID = _CustomAttachment.SalesOrderID
}

/*
  Activating extension views:
  - No modification of SAP standard objects
  - Extensions survive upgrades (SAP does not overwrite extension includes)
  - Activation time: CDS recompilation happens incrementally
*/

sections.codeBlock:
@EndUserText.label: 'Extended Sales Order View'
@AccessControl.authorizationCheck: #CHECK
extend view I_SalesOrder with Z_I_SalesOrder_Extension
{
  Z_CustomField1 as CustomExtensionField1,
  Z_CustomField2 as CustomExtensionField2,

  @Semantics.quantity.unitOfMeasure: 'TotalNetAmountUnit'
  case when Z_CustomField1 is not null
    then TotalNetAmount * Z_CustomField1 / 100
    else TotalNetAmount
  end as AdjustedTotal,

  association [0..*] to Z_CustomSalesAttachment as _CustomAttachment
    on $projection.SalesOrderID = _CustomAttachment.SalesOrderID
}

