@EndUserText.label: 'Sales Order with Full Annotations'
@AccessControl.authorizationCheck: #CHECK

@OData.publish: true
@OData.serviceName: 'Z_SALES_ORDER_SRV'

@UI.headerInfo: {
  typeName: 'Sales Order',
  typeNamePlural: 'Sales Orders',
  title: {
    type: #STANDARD,
    value: 'SalesOrderID'
  },
  description: {
    value: 'Description'
  }
}
@UI.lineItem: [
  { position: 10, label: 'Order', value: 'SalesOrderID' },
  { position: 20, label: 'Customer', value: 'CustomerName' },
  { position: 30, label: 'Amount', value: 'TotalNetAmount' },
  { position: 40, label: 'Date', value: 'CreationDate' }
]

@Analytics.query: true
@Analytics.measure: {
  'TotalNetAmount': {
    aggregation: #SUM,
    currency: 'CurrencyCode'
  }
}
@Analytics.dimension: ['SalesOrganization', 'DistributionChannel', 'Division']

@Search.searchable: true
@Search.fuzziness: 0.8
@Search.decomposition: #DICTIONARY

@Semantics.amount.currencyCode: 'CurrencyCode'
@Semantics.quantity.unitOfMeasure: 'BaseUnit'

define view Z_SalesOrder_Annotations
  as select from I_SalesOrder
{
  key SalesOrderID,
      @Search.tokenize: true
      CustomerName,
      TotalNetAmount,
      CurrencyCode,
      CreationDate,
      SalesOrganization,
      DistributionChannel,
      Division,
      Description
}

/*
  Staff+ Notes:
  - @OData.publish: true auto-generates the OData V4 service.
  - @UI.* annotations drive Fiori elements without SAPUI5 coding.
  - @Analytics enables integration with SAP Analytics Cloud.
  - @Search enables enterprise search without custom index build.
  - One annotation change → rebuild DPC/MPC class at activation.
*/

